    private function parseCsv(UploadedFile $file): array
    {
        $rows = [];
        $handle = fopen($file->getRealPath(), 'r');

        if ($handle === false) {
            return [];
        }

        $headers = null;

        while (($data = fgetcsv($handle)) !== false) {
            if ($headers === null) {
