    {
        $enrollment = new Enrollment(['status' => Enrollment::STATUS_ENROLLED]);
        $this->assertTrue($enrollment->canTransitionTo(Enrollment::STATUS_CANCELLED));
    }

    public function test_enrolled_can_be_completed(): void
    {
        $enrollment = new Enrollment(['status' => Enrollment::STATUS_ENROLLED]);
