        $response->assertStatus(404);
    }

    public function test_field_agent_cannot_import(): void
    {
        $response = $this->withHeaders(['Authorization' => "Bearer {$this->fieldAgentToken}"])
            ->postJson('/api/import/learners', []);

        $response->assertStatus(403);
    }
}
