3	namespace App\Http\Middleware;
4	
5	use Closure;
6	use Illuminate\Http\Request;
7	use Illuminate\Support\Facades\Log;
8	use Symfony\Component\HttpFoundation\Response;
9	
10	class LogRequestResponse
11	{
12	    /**
13	     * Sensitive fields that should not be logged.
14	     */
15	    private const REDACTED_FIELDS = [
16	        'password',
17	        'password_confirmation',
18	        'current_password',
19	        'token',
20	        'authorization',
21	    ];
22	
23	    public function handle(Request $request, Closure $next): Response
24	    {
25	        $startTime = microtime(true);
26	
27	        $response = $next($request);
28	
29	        $duration = round((microtime(true) - $startTime) * 1000, 2);
30	
31	        $this->logRequest($request, $response, $duration);
32	
33	        return $response;
34	    }
35	
36	    private function logRequest(Request $request, Response $response, float $durationMs): void
37	    {
38	        $statusCode = $response->getStatusCode();
39	        $method = $request->method();
40	        $path = $request->path();
41	        $userId = $request->user()?->id;
42	
43	        $context = [
44	            'method' => $method,
45	            'path' => $path,
46	            'status' => $statusCode,
47	            'duration_ms' => $durationMs,
48	            'ip' => $request->ip(),
49	            'user_id' => $userId,
50	            'user_agent' => substr($request->userAgent() ?? '', 0, 200),
51	        ];
52	
53	        // Include sanitized request params for non-GET requests
54	        if (!$request->isMethod('GET')) {
55	            $context['params'] = $this->sanitizeParams($request->all());
56	        }
57	
58	        // Log level based on status code
59	        $message = "{$method} /{$path} → {$statusCode} ({$durationMs}ms)";
60	
61	        if ($statusCode >= 500) {
62	            Log::error($message, $context);
63	        } elseif ($statusCode >= 400) {
64	            Log::warning($message, $context);
65	        } else {
66	            Log::info($message, $context);
67	        }
68	    }
69	
70	    private function sanitizeParams(array $params): array
71	    {
72	        $sanitized = [];
73	
74	        foreach ($params as $key => $value) {
75	            if (in_array(strtolower($key), self::REDACTED_FIELDS)) {
76	                $sanitized[$key] = '[REDACTED]';
77	            } elseif (is_array($value)) {
78	                $sanitized[$key] = $this->sanitizeParams($value);
79	            } else {
80	                $sanitized[$key] = $value;
81	            }
82	        }
83	
84	        return $sanitized;
85	    }
86	}
