46	            );
47	        }
48	
49	        // Check workflow blockers for advancement transitions
50	        if (in_array($newStatus, [Enrollment::STATUS_IN_REVIEW, Enrollment::STATUS_APPROVED])) {
51	            $learner = $enrollment->learner;
52	            $check = ApprovalWorkflow::canAdvance($enrollment->workflow_metadata ?? [], $learner);
53	
54	            if (!$check['can_advance']) {
55	                throw new \InvalidArgumentException(
56	                    'Cannot advance enrollment: ' . implode('; ', $check['blockers'])
57	                );
58	            }
59	        }
60	
61	        return DB::transaction(function () use ($enrollment, $newStatus, $actor, $reasonCode, $notes) {
62	            $previousStatus = $enrollment->status;
63	
64	            $updateData = [
65	                'previous_status' => $previousStatus,
66	                'status' => $newStatus,
67	                'last_actor_id' => $actor->id,
68	                'reason_code' => $reasonCode ?? $enrollment->reason_code,
69	            ];
70	
71	            if ($notes) {
72	                $updateData['notes'] = $notes;
73	            }
74	
75	            // Set timestamps based on transition
76	            switch ($newStatus) {
77	                case Enrollment::STATUS_ENROLLED:
78	                    $updateData['enrolled_at'] = now();
79	                    break;
80	                case Enrollment::STATUS_COMPLETED:
81	                    $updateData['completed_at'] = now();
82	                    break;
83	                case Enrollment::STATUS_CANCELLED:
84	                    $updateData['cancelled_at'] = now();
85	                    break;
86	                case Enrollment::STATUS_REFUNDED:
87	                    $updateData['refunded_at'] = now();
88	                    break;
89	            }
90	
91	            $enrollment->update($updateData);
92	
93	            return $enrollment->fresh();
94	        });
