129	    public function processApproval(Enrollment $enrollment, User $reviewer, string $decision, ?string $comments = null, ?string $reasonCode = null): Enrollment
130	    {
131	        if (!in_array($decision, ['approved', 'rejected'])) {
132	            throw new \InvalidArgumentException("Decision must be 'approved' or 'rejected'.");
133	        }
134	
135	        $currentLevel = $enrollment->current_approval_level;
136	
137	        // Find or create the approval for the current level
138	        $approval = Approval::where('enrollment_id', $enrollment->id)
139	            ->where('level', $currentLevel)
140	            ->first();
141	
142	        if (!$approval) {
143	            $approval = Approval::create([
144	                'enrollment_id' => $enrollment->id,
145	                'reviewer_id' => $reviewer->id,
146	                'level' => $currentLevel,
147	                'status' => 'in_review',
148	            ]);
149	        }
150	
151	        // Record the decision
152	        $approval->update([
153	            'reviewer_id' => $reviewer->id,
154	            'status' => $decision,
155	            'decision' => $decision,
156	            'comments' => $comments,
157	            'reason_code' => $reasonCode,
158	            'decided_at' => now(),
159	        ]);
160	
161	        if ($decision === 'rejected') {
162	            return $this->transition($enrollment, Enrollment::STATUS_REJECTED, $reviewer, $reasonCode ?? 'rejected', $comments);
163	        }
164	
165	        // Approved — check if more levels needed
166	        if ($currentLevel < $enrollment->max_approval_levels) {
