23	    {
24	        parent::setUp();
25	
26	        $role = Role::create(['name' => 'Administrator', 'slug' => 'admin']);
27	        $perms = ['enrollments.create', 'enrollments.view', 'enrollments.update', 'enrollments.approve', 'enrollments.cancel'];
28	        foreach ($perms as $p) {
29	            $perm = Permission::create(['name' => $p, 'slug' => $p]);
30	            $role->permissions()->attach($perm);
31	        }
32	
33	        $user = User::create([
34	            'username' => 'admin', 'name' => 'Admin', 'email' => 'admin@test.com',
35	            'password' => Hash::make('Pass1234!@'), 'role_id' => $role->id, 'is_active' => true,
36	        ]);
37	
38	        $this->token = 'enroll-token-padded-to-exactly-sixty-four-characters-long-here!';
39	        ApiToken::create([
40	            'user_id' => $user->id,
41	            'token' => hash('sha256', $this->token),
42	            'expires_at' => now()->addHours(24),
43	        ]);
44	
45	        $this->learner = Learner::create([
46	            'first_name' => 'John', 'last_name' => 'Doe',
47	            'date_of_birth' => '2000-05-15',
48	        ]);
49	    }
50	
51	    private function auth(): array
52	    {
53	        return ['Authorization' => "Bearer {$this->token}"];
54	    }
