            'status' => 'enrolled',
            'last_actor_id' => $this->admin->id,
            'max_approval_levels' => 1,
            'workflow_metadata' => ['levels' => 1, 'conditions' => []],
        ]);

        $response = $this->withHeaders($this->reviewerAuth())
            ->postJson("/api/enrollments/{$enrollment->id}/cancel");

        $response->assertStatus(403);
    }

