        $response->assertStatus(200);
    }

    public function test_reviewer_cannot_access_approval_assigned_to_others(): void
    {
        $enrollment = Enrollment::create([
            'learner_id' => $this->learner->id,
            'program_name' => 'Test',
            'status' => 'under_review',
            'max_approval_levels' => 1,
